'use client';

import { useEffect, useRef, useState } from "react";

interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  radius: number;
}

export function InteractiveBackground() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const mouseRef = useRef({ x: 0, y: 0 });
  const particlesRef = useRef<Particle[]>([]);
  const [mounted, setMounted] = useState(false);
  const sizeRef = useRef({ width: 0, height: 0, dpr: 1 });

  // Hydration-safe: only render after mount
  useEffect(() => {
    setMounted(true);
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) {
      console.log("Canvas ref not found");
      return;
    }

    const ctx = canvas.getContext("2d");
    if (!ctx) {
      console.log("Canvas context not found");
      return;
    }

    console.log("Canvas initialized successfully");
    console.log("Canvas element:", canvas);
    console.log("Canvas is in document:", document.body.contains(canvas));
    console.log("Canvas parentElement:", canvas.parentElement);
    console.log("Canvas getBoundingClientRect:", canvas.getBoundingClientRect());

    // Set canvas size - match CSS rendered size, handle DPR correctly
    const resizeCanvas = () => {
      const rect = canvas.getBoundingClientRect();
      const dpr = window.devicePixelRatio || 1;

      // store logical size
      sizeRef.current.width = rect.width;
      sizeRef.current.height = rect.height;
      sizeRef.current.dpr = dpr;

      // set internal pixel size
      canvas.width = Math.max(1, Math.floor(rect.width * dpr));
      canvas.height = Math.max(1, Math.floor(rect.height * dpr));

      // reset transform and scale to DPR so drawing uses CSS pixels
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    };

    // Call immediately and on resize
    resizeCanvas();
    window.addEventListener("resize", resizeCanvas);

    // Initialize particles
    const particleCount = window.innerWidth < 768 ? 30 : 60;
    const w = sizeRef.current.width || canvas.getBoundingClientRect().width;
    const h = sizeRef.current.height || canvas.getBoundingClientRect().height;
    particlesRef.current = Array.from({ length: particleCount }, () => ({
      x: Math.random() * w,
      y: Math.random() * h,
      vx: (Math.random() - 0.5) * 0.5,
      vy: (Math.random() - 0.5) * 0.5,
      radius: Math.random() * 3.5 + 2,
    }));

    console.log(`Particles created: ${particleCount}`, particlesRef.current.slice(0, 3));

    // Mouse move handler
    const handleMouseMove = (e: MouseEvent) => {
      mouseRef.current = { x: e.clientX, y: e.clientY };
    };
    window.addEventListener("mousemove", handleMouseMove);

    // Animation loop
    let animationId: number;
    let frameCount = 0;
    const animate = () => {
      frameCount++;
      if (frameCount % 60 === 0) {
        console.log(`Animating frame ${frameCount}, particles: ${particlesRef.current.length}`);
      }

      const w = sizeRef.current.width || canvas.getBoundingClientRect().width;
      const h = sizeRef.current.height || canvas.getBoundingClientRect().height;
      ctx.clearRect(0, 0, w, h);

      // Update and draw particles
      particlesRef.current.forEach((particle, i) => {
        // Move particles
        particle.x += particle.vx;
        particle.y += particle.vy;

        // Bounce off edges
        if (particle.x < 0 || particle.x > (sizeRef.current.width || canvas.getBoundingClientRect().width)) particle.vx *= -1;
        if (particle.y < 0 || particle.y > (sizeRef.current.height || canvas.getBoundingClientRect().height)) particle.vy *= -1;

        // Mouse interaction - attract particles to mouse
        const dx = mouseRef.current.x - particle.x;
        const dy = mouseRef.current.y - particle.y;
        const distance = Math.sqrt(dx * dx + dy * dy);

        if (distance < 150) {
          const force = (150 - distance) / 150;
          particle.vx += (dx / distance) * force * 0.05;
          particle.vy += (dy / distance) * force * 0.05;
        }

        // Apply friction
        particle.vx *= 0.99;
        particle.vy *= 0.99;

        // Draw particle
        ctx.beginPath();
        ctx.arc(particle.x, particle.y, particle.radius, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(99, 102, 241, 0.85)`;
        ctx.fill();

        if (i === 0 && frameCount % 60 === 0) {
          console.log(`Drawing particle at (${particle.x.toFixed(0)}, ${particle.y.toFixed(0)}) with radius ${particle.radius.toFixed(1)}`);
        }

        // Draw connections
        particlesRef.current.forEach((otherParticle, j) => {
          if (i === j) return;

          const dx = particle.x - otherParticle.x;
          const dy = particle.y - otherParticle.y;
          const distance = Math.sqrt(dx * dx + dy * dy);

          if (distance < 120) {
            ctx.beginPath();
            ctx.moveTo(particle.x, particle.y);
            ctx.lineTo(otherParticle.x, otherParticle.y);
            ctx.strokeStyle = `rgba(139, 92, 246, ${(1 - distance / 120) * 0.6})`;
            ctx.lineWidth = 1.2;
            ctx.stroke();
          }
        });

        // Draw connection to mouse if close
        const mouseDistance = Math.sqrt(
          (mouseRef.current.x - particle.x) ** 2 + (mouseRef.current.y - particle.y) ** 2
        );
        if (mouseDistance < 150) {
          ctx.beginPath();
          ctx.moveTo(particle.x, particle.y);
          ctx.lineTo(mouseRef.current.x, mouseRef.current.y);
          ctx.strokeStyle = `rgba(168, 85, 247, ${(1 - mouseDistance / 150) * 0.7})`;
          ctx.lineWidth = 1.5;
          ctx.stroke();

          // Draw glow at mouse
          const gradient = ctx.createRadialGradient(
            mouseRef.current.x,
            mouseRef.current.y,
            0,
            mouseRef.current.x,
            mouseRef.current.y,
            100
          );
          gradient.addColorStop(0, "rgba(168, 85, 247, 0.25)");
          gradient.addColorStop(1, "rgba(168, 85, 247, 0)");
          ctx.fillStyle = gradient;
          ctx.fillRect(mouseRef.current.x - 100, mouseRef.current.y - 100, 200, 200);
        }
      });

      animationId = requestAnimationFrame(animate);
    };
    animate();

    return () => {
      window.removeEventListener("resize", resizeCanvas);
      window.removeEventListener("mousemove", handleMouseMove);
      cancelAnimationFrame(animationId);
    };
  }, [mounted]);

  if (!mounted) return null;

  return (
    <canvas
      ref={canvasRef}
      style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        width: '100%',
        height: '100%',
        border: '3px solid rgba(0,0,255,0.85)',
        display: 'block',
        zIndex: 30,
        pointerEvents: 'none',
        backgroundColor: 'transparent',
      }}
    />
  );
}
